import { clsx, type ClassValue } from 'clsx';
import { twMerge } from 'tailwind-merge';

export function cn(...inputs: ClassValue[]) {
  return twMerge(clsx(inputs));
}

import { GoogleGenAI } from "@google/genai";

export class GeminiService {
  private ai: GoogleGenAI;

  constructor() {
    this.ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
  }

  async generateResponse(prompt: string) {
    try {
      const response = await this.ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: prompt,
        config: {
          systemInstruction: "You are Lumino, a helpful and sophisticated AI assistant integrated into a high-end creative SaaS platform. Your responses should be concise, professional, and highlight the platform's focus on design and efficiency.",
          temperature: 0.7,
        },
      });
      return response.text;
    } catch (error) {
      console.error("Gemini API Error:", error);
      return "I'm having a brief moment of reflection. Please try again in a few seconds.";
    }
  }
}

export const gemini = new GeminiService();

import React, { useState, useEffect } from 'react';
import { Menu, X, Sparkles } from 'lucide-react';
