interface PagesFunction {
  (context: {
    request: Request;
    params: Record<string, string | string[]>;
    env: Record<string, any>;
  }): Promise<Response> | Response;
}

export const onRequest: PagesFunction = async (context) => {
  const { request, params, env } = context;

  // 1. 获取请求路径
  const path = Array.isArray(params.path) ? params.path.join('/') : params.path;

  // 2. 构建目标 URL
  const targetUrl = new URL(`https://generativelanguage.googleapis.com/${path}`);

  // 3. 复制原始查询参数
  const originalUrl = new URL(request.url);
  originalUrl.searchParams.forEach((value, key) => {
    targetUrl.searchParams.set(key, value);
  });

  /**
   * 安全核心：注入服务端 API_KEY
   * 如果客户端没传 key（普通模式），则自动补上 CF Pages 后台配置的 Secret Key
   */
  if (!targetUrl.searchParams.has('key') && env.API_KEY) {
    targetUrl.searchParams.set('key', env.API_KEY);
  }

  // 4. 构造转发请求
  const modifiedRequest = new Request(targetUrl.toString(), {
    method: request.method,
    headers: request.headers,
    body: request.body,
    redirect: 'follow',
  });

  try {
    const response = await fetch(modifiedRequest);
    const newResponse = new Response(response.body, response);

    // 跨域处理
    newResponse.headers.set('Access-Control-Allow-Origin', '*');
    newResponse.headers.set('Access-Control-Allow-Methods', 'GET, POST, OPTIONS');
    newResponse.headers.set('Access-Control-Allow-Headers', 'Content-Type');

    return newResponse;
  } catch (err) {
    return new Response(JSON.stringify({ error: '语枢代理中转失败，请联系管理员。' }), {
      status: 502,
      headers: { 'Content-Type': 'application/json' },
    });
  }
};

