export class GeminiService {
  async generateTeachingResource(prompt: string, type: ToolType = 'general', isPro: boolean = false) {
    /**
     * 初始化逻辑：
     * 1. 专家模式：使用 process.env.API_KEY (用户通过 openSelectKey 选择的 Key)
     * 2. 普通模式：apiKey 传任意字符串，baseUrl 指向本地代理 /api，由后端 Function 注入真实 Key
     */
    const ai = new GoogleGenAI({ 
      apiKey: isPro ? (process.env.API_KEY || '') : 'PROXY_HOLDER',
      baseUrl: isPro ? undefined : `${window.location.origin}/api`
    });

    try {
      const modelName = isPro ? 'gemini-3-pro-preview' : 'gemini-3-flash-preview';

      const response = await ai.models.generateContent({
        model: modelName,
        contents: prompt,
        config: {
          systemInstruction: TOOL_PROMPTS[type] + " 请使用清晰的 Markdown 格式输出，多使用标题、列表和加粗以增强可读性。",
          temperature: 0.7,
        },
      });
      return response.text;
    } catch (error: any) {
      console.error("Gemini API Error:", error);
      // 如果报错显示 entity not found，通常是 Key 失效
      if (error.message?.includes("not found") || error.status === 404) {
        return "ERROR_KEY_INVALID";
      }
      return "语枢智能服务暂时无法处理您的请求，可能是共享额度已耗尽。建议开启【专家模式】使用您的私有 Key。";
    }
  }
}

