interface PagesFunction {
  (context: {
    request: Request;
    params: Record<string, string | string[]>;
    env: Record<string, any>;
  }): Promise<Response> | Response;
}

export const onRequest: PagesFunction = async (context) => {
  const { request, params, env } = context;

  // 1. 解析目标路径（例如 v1beta/models/gemini-3-flash-preview:generateContent）
  const path = Array.isArray(params.path) ? params.path.join('/') : params.path;

  // 2. 构造指向 Google 的真实 URL
  const googleUrl = new URL(`https://generativelanguage.googleapis.com/${path}`);

  // 3. 将原始请求的所有查询参数（Query Params）复制过去
  const clientUrl = new URL(request.url);
  clientUrl.searchParams.forEach((value, key) => {
    googleUrl.searchParams.set(key, value);
  });

  // 4. 安全核心：如果请求中没有带 key 参数，说明是普通用户，我们代为注入服务端 Secret
  if (!googleUrl.searchParams.has('key') && env.API_KEY) {
    googleUrl.searchParams.set('key', env.API_KEY);
  }

  // 5. 转发请求
  const modifiedRequest = new Request(googleUrl.toString(), {
    method: request.method,
    headers: request.headers,
    body: request.body,
    redirect: 'follow',
  });

  try {
    const response = await fetch(modifiedRequest);
    // 构造新的响应以避免 Headers 不可变错误
    const newResponse = new Response(response.body, response);

    // 设置必要的跨域头（虽然同域部署通常不需要，但为了稳妥建议保留）
    newResponse.headers.set('Access-Control-Allow-Origin', '*');

    return newResponse;
  } catch (err) {
    return new Response(JSON.stringify({ error: '语枢代理服务故障，请检查配置。' }), {
      status: 502,
      headers: { 'Content-Type': 'application/json' },
    });
  }
};

import { GoogleGenAI } from "@google/genai";

export type ToolType = 'general' | 'ancient' | 'essay' | 'lesson' | 'reading' | 'poetry';

const TOOL_PROMPTS: Record<ToolType, string> = {
  general: "你是一位资深的语文教学专家。请为老师提供专业的建议、灵感或资源。",
  ancient: "你是一位古典文献学专家。请对输入的文言文进行精准翻译（字对字与意译）、重点实词解析、虚词用法说明，并提取文中的文化常识与艺术特色。",
  poetry: "你是一位精通中国古典诗词的文学评论家与教育专家。请对输入的诗词进行深度鉴赏，重点分析：1. 意境与意象；2. 修辞手法与炼字艺术；3. 作者生平背景及创作时节；4. 核心情感与哲学内涵的深度表达。",
  essay: "你是一位作文阅卷组组长。请从‘语言表达、立意深度、结构逻辑、素材运用’四个维度批改作文。先给出综合评分（百分制），然后列出3个闪光点和2个改进建议，最后提供一段润色后的范文片段。",
  lesson: "你是一位特级语文教师。请根据输入的课文内容或题目，编写一份符合现代教育要求的教案。教案须包含：1. 教学目标（含核心素养）；2. 教学重难点；3. 教学步骤（导入、初读、研读、总结）；4. 课后作业设计。",
  reading: "你是一位阅读推广人。请针对特定书籍或文章，梳理人物关系图谱、核心情节脉络，并设计3个具有思维挑战性的深度探究问题。"
};

export class GeminiService {
  async generateTeachingResource(prompt: string, type: ToolType = 'general', isPro: boolean = false) {
    /**
     * 核心安全逻辑切换：
     * 1. 专家模式 (isPro)：使用 SDK，配合 process.env.API_KEY (用户自带 Key)。
     * 2. 普通模式 (!isPro)：不传递真实 Key，baseUrl 指向本地 /api 代理。
     */

    try {
      const modelName = isPro ? 'gemini-3-pro-preview' : 'gemini-3-flash-preview';
      const systemInst = TOOL_PROMPTS[type] + " 请使用清晰的 Markdown 格式输出。";

      if (isPro) {
        // 专家模式：遵循 SDK 规范
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
        const response = await ai.models.generateContent({
          model: modelName,
          contents: prompt,
          config: { systemInstruction: systemInst, temperature: 0.7 },
        });
        return response.text;
      } else {
        // 普通模式：通过 CF Functions 代理，隐藏 API_KEY
        // 我们手动调用 fetch，因为 SDK 不直接支持更改 BaseURL 的简单方式
        const proxyUrl = `/api/v1beta/models/${modelName}:generateContent`;
        const response = await fetch(proxyUrl, {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({
            contents: [{ parts: [{ text: prompt }] }],
            systemInstruction: { parts: [{ text: systemInst }] },
            generationConfig: { temperature: 0.7 }
          })
        });

        const data = await response.json();
        if (!response.ok) throw new Error(data.error?.message || '代理请求失败');

        // 解析返回的 JSON (Gemini API 标准格式)
        return data.candidates?.[0]?.content?.parts?.[0]?.text || "暂无返回内容";
      }
    } catch (error: any) {
      console.error("Gemini Service Error:", error);
      if (error.message?.includes("not found") || error.status === 404) {
        return "ERROR_KEY_INVALID";
      }
      return "语枢智能服务暂时无法处理您的请求，可能是共享额度已耗尽。建议开启【专家模式】。";
    }
  }
}

