export const AIPortal: React.FC = () => {
  const [messages, setMessages] = useState<Message[]>([
    { role: 'assistant', content: '欢迎来到语枢智慧工作台。请选择工具或直接输入需求。本演示版共享 API 额度，如遇卡顿建议开启【专家模式】。' }
  ]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [activeTool, setActiveTool] = useState<ToolType>('general');
  const [isExpertMode, setIsExpertMode] = useState(false);
  const [copied, setCopied] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, isLoading]);

  const toggleExpertMode = async () => {
    // Check if running inside AI Studio environment
    if (typeof window.aistudio === 'undefined') {
      setMessages(prev => [...prev, { 
        role: 'assistant', 
        content: '💡 温馨提示：专家模式（使用私有 Key）目前仅支持在 Google AI Studio 环境中直接使用。如果您在独立站点访问，请通过 Cloudflare 控制台配置 API_KEY 环境变量。' 
      }]);
      return;
    }

    if (!isExpertMode) {
      try {
        // Safe access due to check above
        await window.aistudio!.openSelectKey();
        setIsExpertMode(true);
        setMessages(prev => [...prev, { role: 'assistant', content: '✨ 专家模式已开启！系统现已接入您的私有 API Key，将使用更强大的 Gemini Pro 模型。' }]);
      } catch (e) {
        console.error("Failed to select key", e);
      }
    } else {
      setIsExpertMode(false);
      setMessages(prev => [...prev, { role: 'assistant', content: '已切回普通模式（共享额度）。' }]);
    }
  };

  const handleSend = async (overridePrompt?: string, forceType?: ToolType) => {
    const textToSend = overridePrompt || input;
    const typeToUse = forceType || activeTool;

    if (!textToSend.trim() || isLoading) return;

    setInput('');
    setMessages(prev => [...prev, { role: 'user', content: textToSend, type: typeToUse }]);
    setIsLoading(true);

    const response = await gemini.generateTeachingResource(textToSend, typeToUse, isExpertMode);

