        role: 'assistant', 
        content: '❌ API Key 校验失败或已过期。' 
      }]);
      setIsExpertMode(false);
      if (typeof window.aistudio !== 'undefined') {
        try { await window.aistudio!.openSelectKey(); } catch (e) {}
      }
