import React, { useState, useEffect } from 'react';
import { Menu, X, Library } from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';
import { cn } from '../lib/utils';

const MotionDiv = motion.div as any;

interface NavbarProps {
  onAuthClick: () => void;
}

export const Navbar: React.FC<NavbarProps> = ({ onAuthClick }) => {
  const [isScrolled, setIsScrolled] = useState(false);
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);

  useEffect(() => {
    const handleScroll = () => setIsScrolled(window.scrollY > 20);
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const navItems = [
    { label: '功能特性', href: '#features' },
    { label: '智能助手', href: '#experience' },
    { label: '资源方案', href: '#pricing' },
  ];

  return (
    <nav className={cn(
      "fixed top-0 left-0 right-0 z-[100] transition-all duration-300 px-6 py-4",
      isScrolled ? "bg-black/80 backdrop-blur-md border-b border-white/5 py-3" : "bg-transparent"
    )}>
      <div className="max-w-7xl mx-auto flex items-center justify-between">
        <div className="flex items-center gap-2 group cursor-pointer" onClick={() => window.scrollTo({top: 0, behavior: 'smooth'})}>
          <div className="w-8 h-8 bg-emerald-600 rounded-lg flex items-center justify-center group-hover:rotate-12 transition-transform">
            <Library className="w-5 h-5 text-white" />
          </div>
          <span className="text-xl font-bold tracking-tight">语枢<span className="text-emerald-500">AI</span></span>
        </div>

        <div className="hidden md:flex items-center gap-8">
          {navItems.map((item) => (
            <a key={item.label} href={item.href} className="text-sm font-medium text-white/70 hover:text-white transition-colors">{item.label}</a>
          ))}
          <button 
            onClick={onAuthClick}
            className="px-5 py-2 bg-emerald-600 text-white text-sm font-semibold rounded-full hover:bg-emerald-500 transition-all active:scale-95"
          >
            免费体验
          </button>
        </div>

        <button className="md:hidden p-2 text-white/70" onClick={() => setIsMobileMenuOpen(!isMobileMenuOpen)}>
          {isMobileMenuOpen ? <X /> : <Menu />}
        </button>
      </div>

      <AnimatePresence>
        {isMobileMenuOpen && (
          <MotionDiv 
            initial={{ opacity: 0, height: 0 }} 
            animate={{ opacity: 1, height: 'auto' }} 
            exit={{ opacity: 0, height: 0 }} 
            className="absolute top-full left-0 right-0 bg-black/95 backdrop-blur-xl border-b border-white/10 flex flex-col p-6 gap-6 md:hidden overflow-hidden"
          >
            {navItems.map((item) => (
              <a key={item.label} href={item.href} className="text-lg font-medium text-white/70" onClick={() => setIsMobileMenuOpen(false)}>{item.label}</a>
            ))}
            <button onClick={() => { setIsMobileMenuOpen(false); onAuthClick(); }} className="w-full py-3 bg-emerald-600 text-white font-semibold rounded-xl">立即开始</button>
          </MotionDiv>
        )}
      </AnimatePresence>
    </nav>
  );
};

